spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 8000;
    var progress = (t % duration) / duration;

    var p1 = 0.20; // 0 to 2s: Display 168
    var p2 = 0.45; // 2s to 4.5s: Split into 1 + 6 + 8 = 15
    var p3 = 0.70; // 4.5s to 7s: Test 3
    var p4 = 0.95; // 7s to 9.5s: Test 9

    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    // Top original number
    ctx.fillStyle = '#F3F4F6';
    ctx.font = 'bold 28px -apple-system, sans-serif';
    ctx.fillText('168', W / 2, H * 0.20);

    if (progress < p1) {
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '14px -apple-system, sans-serif';
      ctx.fillText('Let\'s test 168 for divisibility by 3 and 9...', W / 2, H * 0.40);
    }

    // Digit sum expansion
    if (progress >= p1) {
      var tVal = (progress - p1) / (p2 - p1);
      tVal = Math.min(1.0, tVal);

      var dx = 40 * tVal;
      ctx.fillStyle = '#60A5FA';
      ctx.font = 'bold 20px -apple-system, sans-serif';

      // Draw '1', '+', '6', '+', '8'
      ctx.fillText('1', W / 2 - dx, H * 0.42);
      if (tVal > 0.5) ctx.fillText('+', W / 2 - dx/2, H * 0.42);
      ctx.fillText('6', W / 2, H * 0.42);
      if (tVal > 0.5) ctx.fillText('+', W / 2 + dx/2, H * 0.42);
      ctx.fillText('8', W / 2 + dx, H * 0.42);

      if (progress >= p2) {
        ctx.fillStyle = '#FBBF24';
        ctx.font = 'bold 22px -apple-system, sans-serif';
        ctx.fillText(' = 15', W / 2, H * 0.55);
      }
    }

    // Divisibility by 3 check
    if (progress >= p2) {
      ctx.font = 'bold 13px -apple-system, sans-serif';
      if (progress >= p2 && progress < p3) {
        ctx.fillStyle = '#9CA3AF';
        ctx.fillText('Is the sum 15 divisible by 3?', W / 2, H * 0.70);
      } else if (progress >= p3) {
        ctx.fillStyle = '#34D399';
        ctx.fillText('15 / 3 = 5 (R 0)  ✔  Divisible by 3!', W / 2, H * 0.70);

        // Divisibility by 9 check
        if (progress >= p3 && progress < p4) {
          ctx.fillStyle = '#9CA3AF';
          ctx.fillText('Is the sum 15 divisible by 9?', W / 2, H * 0.82);
        } else if (progress >= p4) {
          ctx.fillStyle = '#F87171';
          ctx.fillText('15 / 9 = 1 (R 6)  ✘  NOT divisible by 9!', W / 2, H * 0.82);
        }
      }
    }
  }
};
